class SafeSingleton:
    _instance = None
    _lock = threading.Lock()
    def __new__(cls):
        try:
            with cls._lock:
                if not cls._instance:
                    cls._instance = super().__new__(cls)
            return cls._instance
        except Exception as e:
            raise RuntimeError(f'Failed: {e}')
